mapper.delete:
delete
from tbl_bookmark
where member_id = #{memberId}
  and post_id = #{postId}

mapper.update:
update tbl_bookmark
set folder_id = null
where folder_id = #{folderId}

update tbl_bookmark
set folder_id = #{folderId}
where id = #{id}

mapper.select:
select b.id, b.member_id, b.post_id, b.folder_id, b.created_datetime
from tbl_bookmark b
where b.id = #{id}

select b.id, b.member_id, b.post_id, b.folder_id, b.created_datetime
from tbl_bookmark b
where b.member_id = #{memberId}
  and b.post_id = #{postId}

select id, member_id, post_id, news_id, bookmark_type, folder_id, created_datetime,
       post_member_id, post_title, post_content, member_nickname, member_handle,
       member_profile_file_name, like_count, reply_count, bookmark_count, liked
from (
    select ,
           case when exists (
               select 1 from tbl_post_like pl2
               where pl2.post_id = p.id and pl2.member_id = #{memberId}
           ) then 1 else 0 end as liked
    from tbl_bookmark b
             left join tbl_post p on b.post_id = p.id
             left join tbl_member m on p.member_id = m.id
    where b.member_id = #{memberId}
      and not exists (
          select 1 from tbl_report r
          where r.target_id = p.id and r.reporter_id = #{memberId} and r.target_type = 'post'
      )
    union all
    select ,
           case when exists (
               select 1 from tbl_news_like nl2
               where nl2.news_id = n.id and nl2.member_id = #{memberId}
           ) then 1 else 0 end as liked
    from tbl_news_bookmark nb
             left join tbl_news n on nb.news_id = n.id
    where nb.member_id = #{memberId}
) merged
order by created_datetime desc

select id, member_id, post_id, news_id, bookmark_type, folder_id, created_datetime,
       post_member_id, post_title, post_content, member_nickname, member_handle,
       member_profile_file_name, like_count, reply_count, bookmark_count, liked
from (
    select ,
           case when exists (
               select 1 from tbl_post_like pl2
               where pl2.post_id = p.id and pl2.member_id = #{memberId}
           ) then 1 else 0 end as liked
    from tbl_bookmark b
             left join tbl_post p on b.post_id = p.id
             left join tbl_member m on p.member_id = m.id
    where b.member_id = #{memberId}
      and b.folder_id is null
      and not exists (
          select 1 from tbl_report r
          where r.target_id = p.id and r.reporter_id = #{memberId} and r.target_type = 'post'
      )
    union all
    select ,
           case when exists (
               select 1 from tbl_news_like nl2
               where nl2.news_id = n.id and nl2.member_id = #{memberId}
           ) then 1 else 0 end as liked
    from tbl_news_bookmark nb
             left join tbl_news n on nb.news_id = n.id
    where nb.member_id = #{memberId}
      and nb.folder_id is null
) merged
order by created_datetime desc

select count(*)
from tbl_bookmark
where member_id = #{memberId}
